export function getBundledMapDataset(language: string): MapDataset {
  const useZh = language.toLowerCase().startsWith("zh");
  return {
    buildNumber: MAP_BUILD_NUMBER,
    regions: (useZh ? REGIONS_ZH : REGIONS_EN) as unknown as MapDataset["regions"],
    constellations: (useZh ? CONSTELLATIONS_ZH : CONSTELLATIONS_EN) as unknown as MapDataset["constellations"],
    systems: (useZh ? SYSTEMS_ZH : SYSTEMS_EN) as unknown as MapDataset["systems"],
    edges: STARGATE_EDGES as unknown as MapDataset["edges"],
  };
}
